/** Find the dept the current pathname belongs to (or null). */
export function deptForPath(pathname: string): Dept | null {
  if (pathname.startsWith("/ops")) return "ops";
  if (pathname.startsWith("/finance")) return "finance";
  if (pathname.startsWith("/growth")) return "growth";
  if (pathname.startsWith("/customers")) return "customers";
  if (pathname.startsWith("/data")) return "data";
  return null;
}

/** Find the active subnav item id for a given pathname under a dept. */
export function activeSubnavItem(data: DeptSubnavData, pathname: string): string | null {
  const allItems = data.sections.flatMap((s) => s.items);
  const sorted = [...allItems].sort((a, b) => b.href.length - a.href.length);
  for (const item of sorted) {
    if (pathname === item.href || pathname.startsWith(item.href + "/")) {
      return item.id;
    }
  }
  return null;
}
