const ALL_ROOMS = [...PERSONAL_ROOMS, ...DEPT_ROOMS];

function RailItem({ room, isActive }: { room: Room; isActive: boolean }) {
  const [hover, setHover] = useState(false);
  const color = isActive
    ? room.accent
    : hover
      ? "rgba(243,241,235,0.82)"
      : "rgba(243,241,235,0.42)";
  return (
    <Link href={room.href} aria-label={room.label}>
      <div
        className={styles.item}
        onMouseEnter={() => setHover(true)}
        onMouseLeave={() => setHover(false)}
        style={{
          color,
          borderLeftColor: isActive ? room.accent : "transparent",
          background: isActive
            ? "linear-gradient(90deg, rgba(255,255,255,0.045) 0%, transparent 70%)"
            : "transparent",
        }}
      >
        <span className={styles.itemIcon}>{room.icon}</span>
        {room.label}
      </div>
    </Link>
  );
}

