"use client";

/**
 * Morning Brief Dock — the fixed compact bar at the bottom of every page.
 *
 * Ported from `magellan-growth (19).html` (the dock CSS lives next to this
 * file). Hidden on /study and while the Bridge overlay is open. The
 * expanded conversation panel / brief panel / quick popover from the
 * source are NOT in this slice — only the compact bar.
 *
 * Doors:
 *   Bridge → opens the existing BridgeOverlay (useBridge)
 *   Study  → routes to /study (route may be a stub)
 */

import { useEffect, useRef, useState } from "react";
import { useRouter, usePathname } from "next/navigation";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import "./MorningBriefDock.css";

const ROTATING_PLACEHOLDERS = [
  "Ask Magellan anything…",
  "What's my true ROAS?",
  "Which campaigns are losing money?",
  "How's the Valentine creative doing?",
  "What's today's revenue?",
];

export function MorningBriefDock() {
  const router = useRouter();
  const pathname = usePathname();
  const { open: bridgeOpen, openBridge } = useBridge();

  const inputRef = useRef<HTMLInputElement>(null);
  const [value, setValue] = useState("");
  const [phIdx, setPhIdx] = useState(0);
  const [phFade, setPhFade] = useState(false);
  const [briefConsumed, setBriefConsumed] = useState(false);

  // Hide on Study, hide when Bridge overlay is open.
  const hidden = pathname.startsWith("/study") || bridgeOpen;

  // Rotate placeholder every 3.5s — pause while focused or with text.
  useEffect(() => {
    if (hidden) return;
    const id = window.setInterval(() => {
      if (document.activeElement === inputRef.current) return;
      if (value) return;
      setPhFade(true);
      window.setTimeout(() => {
        setPhIdx((i) => (i + 1) % ROTATING_PLACEHOLDERS.length);
        setPhFade(false);
      }, 350);
    }, 3500);
    return () => window.clearInterval(id);
  }, [hidden, value]);

  const handleBridge = () => openBridge();
  const handleStudy = () => router.push("/study");
  const handleBrief = () => setBriefConsumed(true);

  return (
    <div
      className={`mag-dock${hidden ? " hidden" : ""}`}
      id="mag-dock"
      aria-hidden={hidden}
    >
      <div
        className="mag-dock-m"
        role="img"
        aria-label="Magellan"
        title="Magellan"
      />

      <button
        type="button"
        className={`mag-brief-light${briefConsumed ? " consumed" : ""}`}
        title="Play today's brief"
        onClick={handleBrief}
      >
        <span className="mag-brief-dot" />
        <span className="mag-brief-play-icon">
          <svg viewBox="0 0 24 24" fill="currentColor">
            <polygon points="6 4 20 12 6 20 6 4" />
          </svg>
        </span>
        Brief
      </button>

      <div
        className={`mag-dock-input-wrap${value ? " has-text" : ""}`}
        onClick={() => inputRef.current?.focus()}
      >
        <span className={`mag-dock-ph${phFade ? " fade-out" : ""}`}>
          {ROTATING_PLACEHOLDERS[phIdx]}
        </span>
        <input
          ref={inputRef}
          className="mag-dock-input"
          type="text"
          autoComplete="off"
          value={value}
          onChange={(e) => setValue(e.target.value)}
        />
      </div>

      <div className="mag-dock-doors">
        <button
          type="button"
          className="mag-dock-door bridge"
          title="Open the Bridge — act & execute"
          onClick={handleBridge}
        >
          Bridge<span className="mag-dock-door-arrow">→</span>
        </button>
        <button
          type="button"
          className="mag-dock-door"
          title="Open Study — build & think"
          onClick={handleStudy}
        >
          <span className="mag-dock-door-icon">
            <svg
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="1.8"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M2 4h7a3 3 0 0 1 3 3v13a2 2 0 0 0-2-2H2zM22 4h-7a3 3 0 0 0-3 3v13a2 2 0 0 1 2-2h8z" />
            </svg>
          </span>
          Study
        </button>
      </div>
    </div>
  );
}
