"use client";

/* ════════════════════════════════════════════════════════════════════════
   DeptSubnav — sticky left panel between rail and main.

   TWO MODES — user pref persisted to localStorage:

   1. PINNED (default) — 256px column always visible in flex flow.
      Click the pin in the head to unpin.

   2. UNPINNED — collapses to a 24px trigger strip.
      • Hover the strip → panel expands (pushes content right)
      • Move mouse to a new room from the rail → panel AUTO-OPENS for ~2.5s
        so the user sees what's in the new room without having to hunt
      • Mouse leave OR navigating to a sibling page → panel collapses back
      • Click the pin in the head to re-pin

   PUSH layout — the panel lives in flex flow, so when expanded it shifts
   main content right rather than floating over it. No overlay, no z-index
   fights with content.

   Returns null on non-dept routes (Today, Study, Settings).
   ════════════════════════════════════════════════════════════════════════ */

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import {
  DEPT_SUBNAV,
  deptForPath,
  activeSubnavItem,
} from "@/lib/dept-subnav-data";
import { useSubnavPin } from "@/lib/use-subnav-pin";

const AUTO_OPEN_MS = 2500;

export function DeptSubnav() {
  const pathname = usePathname();
  const [pinned, setPinned] = useSubnavPin();
  const dept = deptForPath(pathname);

  const [autoOpen, setAutoOpen] = useState(false);
  const [hover, setHover] = useState(false);
  const lastDept = useRef<typeof dept>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  // Auto-open the panel briefly when the user enters a new dept (unpinned only).
  useEffect(() => {
    if (!dept || pinned) {
      lastDept.current = dept;
      return;
    }
    if (dept === lastDept.current) return;
    lastDept.current = dept;
    setAutoOpen(true);
    if (timerRef.current) clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => setAutoOpen(false), AUTO_OPEN_MS);
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [dept, pinned]);

  if (!dept) return null;
  const data = DEPT_SUBNAV[dept];
  if (!data) return null;
  const activeId = activeSubnavItem(data, pathname);

  const expanded = pinned || hover || autoOpen;

  const handleLeave = () => {
    setHover(false);
    // Mouse moved away — drop any pending auto-open so the panel collapses now.
    if (autoOpen) {
      setAutoOpen(false);
      if (timerRef.current) clearTimeout(timerRef.current);
    }
  };

  return (
    <aside
      className="subnav"
      data-pin={pinned ? "pinned" : "unpinned"}
      data-expanded={expanded ? "true" : "false"}
      data-d={dept}
      aria-label={`${data.title} sections`}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={handleLeave}
    >
      {/* Trigger strip — only shown when unpinned + collapsed */}
      <div className="subnav-strip" aria-hidden={expanded}>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round">
          <polyline points="9 6 15 12 9 18" />
        </svg>
      </div>

      {/* Main panel */}
      <div className="subnav-panel" aria-hidden={!expanded}>
        <div className="subnav-head">
          <div className="subnav-title">{data.title}</div>
          <button
            className={`subnav-anchor${pinned ? " pinned" : ""}`}
            onClick={() => setPinned(!pinned)}
            aria-label={pinned ? "Unpin panel — collapse to trigger strip" : "Pin panel — keep open"}
            title={pinned ? "Click to unpin (auto-hide on mouse out)" : "Click to pin open"}
            type="button"
          >
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="12" cy="5" r="2" fill={pinned ? "currentColor" : "none"} />
              <line x1="12" y1="7" x2="12" y2="20" />
              <line x1="8" y1="11" x2="16" y2="11" />
              <path d="M5 14a7 7 0 0 0 7 6 7 7 0 0 0 7 -6" />
            </svg>
          </button>
        </div>

        <div className="subnav-scroll">
          {data.sections.map((section, i) => (
            <div key={i}>
              {section.label && <div className="subnav-section">{section.label}</div>}
              {section.items.map((item) => (
                <Link
                  key={item.id}
                  href={item.href}
                  className={`subnav-item${item.id === activeId ? " active" : ""}${item.home ? " home" : ""}`}
                >
                  <span className="ico">{item.icon}</span>
                  <span className="lbl">{item.label}</span>
                  {item.badge && (
                    <span className={`badge${item.badgeAlert ? " alert" : ""}`}>
                      {item.badge}
                    </span>
                  )}
                </Link>
              ))}
            </div>
          ))}
        </div>

        {data.connections && data.connections.length > 0 && (
          <div className="subnav-foot">
            <div className="subnav-foot-label">Connections</div>
            {data.connections.map((c, i) => (
              <div key={i} className="conn-row">
                <span className="conn-dot" />
                <span className="conn-name">{c.name}</span>
                {c.tag && <span className="conn-tag">{c.tag}</span>}
              </div>
            ))}
          </div>
        )}
      </div>
    </aside>
  );
}
