"use client";

/**
 * Root-level client providers.
 *
 * Sits at the top of the layout tree (just inside <body>) so any Client
 * Component below it can use TanStack Query. The QueryClient is built
 * once per mount via useState so it survives re-renders but doesn't
 * leak across navigations.
 *
 * Defaults are tuned for a comparison-heavy analytics UI: data is
 * considered fresh for a minute (avoids refetch storms on tab focus),
 * retries once on failure (no thrashing if the API is down).
 */

import { useState, type ReactNode } from "react";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";

export function Providers({ children }: { children: ReactNode }) {
  const [client] = useState(
    () =>
      new QueryClient({
        defaultOptions: {
          queries: {
            staleTime: 60_000,
            gcTime: 5 * 60_000,
            refetchOnWindowFocus: false,
            retry: 1,
          },
        },
      }),
  );
  return <QueryClientProvider client={client}>{children}</QueryClientProvider>;
}
