"use client";

/**
 * App chrome wrapper.
 *
 * Renders the Rail / DeptSubnav / MorningBriefDock around the page on
 * authenticated routes, and gets out of the way on /signin and /auth/*
 * so the sign-in screen stands alone. Lives as a Client Component so
 * we can read the pathname without restructuring the route tree into
 * multiple root layouts.
 */

import { usePathname } from "next/navigation";
import { Rail } from "@/components/Rail";
import { DeptSubnav } from "@/components/shared/DeptSubnav";
import { MorningBriefDock } from "@/components/dock/MorningBriefDock";

const BARE_PREFIXES = ["/signin", "/auth"];

export function AppChrome({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const bare = BARE_PREFIXES.some((p) => pathname === p || pathname.startsWith(`${p}/`));

  if (bare) {
    return <>{children}</>;
  }

  return (
    <>
      <Rail />
      <DeptSubnav />
      <main style={{ flex: 1, minHeight: "100vh", position: "relative", minWidth: 0, paddingBottom: 104 }}>
        {children}
      </main>
      <MorningBriefDock />
    </>
  );
}
